# solution.py
import copy
import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    pass


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Data classes (plain objects -- mutable by callers as spec requires)
# ---------------------------------------------------------------------------
class Attachment:
    def __init__(self, filename, size, uploaded_by, uploaded_at):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at


class User:
    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at


class Project:
    def __init__(self, id, name, description, start_date, end_date, owner_id):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id


class Task:
    def __init__(self, id, project_id, title, status, assignee_id, deadline,
                 started_at, completed_at, description, created_at):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = started_at
        self.completed_at = completed_at
        self.description = description
        self.created_at = created_at


class Message:
    def __init__(self, id, author_id, body, project_id, task_id, parent_id,
                 attachments, created_at, edited_at):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments
        self.created_at = created_at
        self.edited_at = edited_at


class Rating:
    def __init__(self, id, rater_id, ratee_id, score, feedback, task_id, created_at):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at


# ---------------------------------------------------------------------------
# Sub-store: lightweight container whose only role is to expose ._lock
# ---------------------------------------------------------------------------
class _Store:
    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# Main class
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    def __init__(self, now=None):
        self._now = now if now is not None else datetime.utcnow

        self._lock = threading.RLock()

        # Sub-store objects that expose the shared lock (test: id equality)
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # Per-instance ID counter (starts at 0; first entity gets id 1)
        self._id_counter = 0

        # Primary stores
        self._users = {}            # id -> User
        self._users_by_name = {}    # username -> id
        self._users_by_email = {}   # email -> id
        self._projects = {}         # id -> Project
        self._tasks = {}            # id -> Task
        self._messages = {}         # id -> Message
        self._ratings = []          # list[Rating]

        # Indexes
        self._tasks_by_project = {}     # project_id -> list[task_id]
        self._tasks_by_assignee = {}    # user_id -> set[task_id]
        self._messages_by_project = {}  # project_id -> list[msg_id]
        self._messages_by_task = {}     # task_id -> list[msg_id]

    # ------------------------------------------------------------------
    # Internal helpers (called only while lock is already held)
    # ------------------------------------------------------------------
    def _alloc_id(self):
        self._id_counter += 1
        return self._id_counter

    # ------------------------------------------------------------------
    # Users
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not isinstance(username, str):
                raise ValidationError("Username cannot be empty")
            username = username.strip()
            if not username:
                raise ValidationError("Username cannot be empty")
            if not isinstance(email, str) or "@" not in email:
                raise ValidationError("Invalid email")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole instance")
            if username in self._users_by_name:
                raise DuplicateError("Username already taken")
            if email in self._users_by_email:
                raise DuplicateError("Email already taken")

            uid = self._alloc_id()
            user = User(uid, username, email, role, self._now())
            self._users[uid] = user
            self._users_by_name[username] = uid
            self._users_by_email[email] = uid
            return copy.deepcopy(user)

    def get_user(self, id):
        with self._lock:
            if id not in self._users:
                raise NotFoundError("User not found")
            return copy.deepcopy(self._users[id])

    def list_users(self):
        with self._lock:
            return [copy.deepcopy(u)
                    for u in sorted(self._users.values(), key=lambda u: u.id)]

    def update_user(self, id, username=None, email=None, role=None):
        with self._lock:
            if id not in self._users:
                raise NotFoundError("User not found")
            user = self._users[id]

            # Validate all before mutating
            if username is not None:
                if not isinstance(username, str):
                    raise ValidationError("Username cannot be empty")
                username = username.strip()
                if not username:
                    raise ValidationError("Username cannot be empty")
                if username != user.username and username in self._users_by_name:
                    raise DuplicateError("Username already taken")
            if email is not None:
                if not isinstance(email, str) or "@" not in email:
                    raise ValidationError("Invalid email")
                if email != user.email and email in self._users_by_email:
                    raise DuplicateError("Email already taken")

            # Apply
            if username is not None:
                del self._users_by_name[user.username]
                user.username = username
                self._users_by_name[username] = id
            if email is not None:
                del self._users_by_email[user.email]
                user.email = email
                self._users_by_email[email] = id
            if role is not None:
                user.role = role

            return copy.deepcopy(user)

    def delete_user(self, id):
        with self._lock:
            if id not in self._users:
                raise NotFoundError("User not found")
            for project in self._projects.values():
                if project.owner_id == id:
                    raise ConflictError("User owns a project")
            task_ids = self._tasks_by_assignee.get(id, set())
            for tid in task_ids:
                task = self._tasks.get(tid)
                if task and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("User has open tasks")
            user = self._users.pop(id)
            del self._users_by_name[user.username]
            del self._users_by_email[user.email]
            self._tasks_by_assignee.pop(id, None)

    # ------------------------------------------------------------------
    # Projects
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if owner_id not in self._users:
                raise NotFoundError("Owner not found")
            if not name or not name.strip():
                raise ValidationError("Name cannot be empty")
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")

            pid = self._alloc_id()
            project = Project(pid, name, description, start_date, end_date, owner_id)
            self._projects[pid] = project
            self._tasks_by_project[pid] = []
            self._messages_by_project[pid] = []
            return copy.deepcopy(project)

    def get_project(self, id):
        with self._lock:
            if id not in self._projects:
                raise NotFoundError("Project not found")
            return copy.deepcopy(self._projects[id])

    def list_projects(self):
        with self._lock:
            return [copy.deepcopy(p)
                    for p in sorted(self._projects.values(), key=lambda p: p.id)]

    def update_project(self, id, name=None, start_date=None, end_date=None,
                       description=None):
        with self._lock:
            if id not in self._projects:
                raise NotFoundError("Project not found")
            project = self._projects[id]

            # Compute resulting values for validation
            new_name = name if name is not None else project.name
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date

            if name is not None and (not new_name or not new_name.strip()):
                raise ValidationError("Name cannot be empty")
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            # Apply
            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description

            return copy.deepcopy(project)

    def delete_project(self, id):
        with self._lock:
            if id not in self._projects:
                raise NotFoundError("Project not found")

            # Cascade: delete tasks (and their task-level messages)
            for tid in list(self._tasks_by_project.get(id, [])):
                task = self._tasks.pop(tid, None)
                if task and task.assignee_id is not None:
                    self._tasks_by_assignee.get(task.assignee_id, set()).discard(tid)
                for mid in list(self._messages_by_task.get(tid, [])):
                    self._messages.pop(mid, None)
                self._messages_by_task.pop(tid, None)
            self._tasks_by_project.pop(id, None)

            # Cascade: delete project-level messages
            for mid in list(self._messages_by_project.get(id, [])):
                self._messages.pop(mid, None)
            self._messages_by_project.pop(id, None)

            del self._projects[id]

    # ------------------------------------------------------------------
    # Tasks
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None,
                    description=""):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found")
            if not title or not title.strip():
                raise ValidationError("Title cannot be empty")
            if assignee_id is not None and assignee_id not in self._users:
                raise NotFoundError("Assignee not found")
            project = self._projects[project_id]
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("Deadline before project start")

            tid = self._alloc_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                description=description,
                created_at=self._now(),
            )
            self._tasks[tid] = task
            self._tasks_by_project[project_id].append(tid)
            if assignee_id is not None:
                self._tasks_by_assignee.setdefault(assignee_id, set()).add(tid)
            return copy.deepcopy(task)

    def get_task(self, id):
        with self._lock:
            if id not in self._tasks:
                raise NotFoundError("Task not found")
            return copy.deepcopy(self._tasks[id])

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found")
            tids = self._tasks_by_project.get(project_id, [])
            tasks = [self._tasks[t] for t in tids if t in self._tasks]
            return [copy.deepcopy(t) for t in sorted(tasks, key=lambda t: t.id)]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            if assignee_id not in self._users:
                raise NotFoundError("User not found")
            tids = self._tasks_by_assignee.get(assignee_id, set())
            tasks = [self._tasks[t] for t in tids if t in self._tasks]
            return [copy.deepcopy(t) for t in sorted(tasks, key=lambda t: t.id)]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found")
            if assignee_id not in self._users:
                raise NotFoundError("Assignee not found")
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                self._tasks_by_assignee.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = assignee_id
            self._tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id):
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found")
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                self._tasks_by_assignee.get(task.assignee_id, set()).discard(task_id)
                task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline_or_None):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found")
            task = self._tasks[task_id]
            if deadline_or_None is not None:
                project = self._projects[task.project_id]
                if deadline_or_None < project.start_date:
                    raise ValidationError("Deadline before project start")
            task.deadline = deadline_or_None
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found")
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus instance")
            task = self._tasks[task_id]
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            if author_id not in self._users:
                raise NotFoundError("Author not found")
            if project_id is None and task_id is None:
                raise ValidationError("Exactly one of project_id or task_id required")
            if project_id is not None and task_id is not None:
                raise ValidationError("Exactly one of project_id or task_id required")
            if project_id is not None and project_id not in self._projects:
                raise NotFoundError("Project not found")
            if task_id is not None and task_id not in self._tasks:
                raise NotFoundError("Task not found")
            if parent_id is not None and parent_id not in self._messages:
                raise NotFoundError("Parent message not found")

            atts = []
            if attachments:
                for filename, data in attachments:
                    atts.append(Attachment(filename, len(data), author_id, self._now()))

            if not body and not atts:
                raise ValidationError("Body cannot be empty when no attachments")

            mid = self._alloc_id()
            msg = Message(
                id=mid,
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=atts,
                created_at=self._now(),
                edited_at=None,
            )
            self._messages[mid] = msg
            if project_id is not None:
                self._messages_by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self._messages_by_task.setdefault(task_id, []).append(mid)
            return copy.deepcopy(msg)

    def edit_message(self, msg_id, editor_id, new_body):
        with self._lock:
            if msg_id not in self._messages:
                raise NotFoundError("Message not found")
            msg = self._messages[msg_id]
            if msg.author_id != editor_id:
                raise AuthorizationError("Not authorized")
            if not new_body and not msg.attachments:
                raise ValidationError("Body cannot be empty when no attachments")
            msg.body = new_body
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(self, msg_id, uploader_id, filename, data_bytes):
        with self._lock:
            if msg_id not in self._messages:
                raise NotFoundError("Message not found")
            msg = self._messages[msg_id]
            if msg.author_id != uploader_id:
                raise AuthorizationError("Not authorized")
            if not filename:
                raise ValidationError("Filename cannot be empty")
            att = Attachment(filename, len(data_bytes), uploader_id, self._now())
            msg.attachments.append(att)
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found")
            mids = self._messages_by_project.get(project_id, [])
            msgs = [self._messages[m] for m in mids if m in self._messages]
            return [copy.deepcopy(m) for m in sorted(msgs, key=lambda m: m.id)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found")
            mids = self._messages_by_task.get(task_id, [])
            msgs = [self._messages[m] for m in mids if m in self._messages]
            return [copy.deepcopy(m) for m in sorted(msgs, key=lambda m: m.id)]

    def delete_message(self, msg_id, requester_id):
        with self._lock:
            if msg_id not in self._messages:
                raise NotFoundError("Message not found")
            msg = self._messages[msg_id]
            if msg.author_id != requester_id:
                raise AuthorizationError("Not authorized")
            if msg.project_id is not None:
                lst = self._messages_by_project.get(msg.project_id, [])
                if msg_id in lst:
                    lst.remove(msg_id)
            if msg.task_id is not None:
                lst = self._messages_by_task.get(msg.task_id, [])
                if msg_id in lst:
                    lst.remove(msg_id)
            del self._messages[msg_id]

    # ------------------------------------------------------------------
    # Performance
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found")
            tids = self._tasks_by_assignee.get(user_id, set())
            tasks = [self._tasks[t] for t in tids if t in self._tasks]
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found")
            tids = self._tasks_by_assignee.get(user_id, set())
            times = [
                (self._tasks[t].completed_at - self._tasks[t].started_at).total_seconds()
                for t in tids
                if t in self._tasks
                and self._tasks[t].status == TaskStatus.COMPLETED
                and self._tasks[t].started_at is not None
                and self._tasks[t].completed_at is not None
            ]
            return sum(times) / len(times) if times else None

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id not in self._users:
                raise NotFoundError("Rater not found")
            if ratee_id not in self._users:
                raise NotFoundError("Ratee not found")
            if rater_id == ratee_id:
                raise ConflictError("Cannot rate yourself")
            if not isinstance(score, int) or isinstance(score, bool) or score < 1 or score > 5:
                raise ValidationError("Score must be integer 1-5")
            if task_id is not None and task_id not in self._tasks:
                raise NotFoundError("Task not found")
            rid = self._alloc_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self._ratings.append(rating)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found")
            ratings = [r for r in self._ratings if r.ratee_id == user_id]
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found")
            tids = self._tasks_by_assignee.get(user_id, set())
            tasks = [self._tasks[t] for t in tids if t in self._tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = completed / total if total else 0.0
            times = [
                (t.completed_at - t.started_at).total_seconds()
                for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None and t.completed_at is not None
            ]
            avg_time = sum(times) / len(times) if times else None
            ratings = [r for r in self._ratings if r.ratee_id == user_id]
            rating_count = len(ratings)
            rating_average = sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found")
            tids = self._tasks_by_project.get(project_id, [])
            tasks = [self._tasks[t] for t in tids if t in self._tasks]
            total = len(tasks)
            status_counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            for t in tasks:
                status_counts[t.status.value] += 1
            completed_count = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed_count / total if total else 0.0
            now = self._now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )
            per_assignee = {}
            for t in tasks:
                if t.assignee_id is not None and t.assignee_id in self._users:
                    a = t.assignee_id
                    if a not in per_assignee:
                        per_assignee[a] = {"total": 0, "completed": 0}
                    per_assignee[a]["total"] += 1
                    if t.status == TaskStatus.COMPLETED:
                        per_assignee[a]["completed"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self._projects:
                raise NotFoundError("Project not found")
            if project_id is not None:
                tids = self._tasks_by_project.get(project_id, [])
                scoped = [self._tasks[t] for t in tids if t in self._tasks]
            else:
                scoped = list(self._tasks.values())
            by_user = {}
            for t in scoped:
                if t.assignee_id is not None:
                    by_user.setdefault(t.assignee_id, []).append(t)
            rows = []
            for uid, utasks in by_user.items():
                user = self._users.get(uid)
                if user is None:
                    continue
                total = len(utasks)
                completed = sum(1 for t in utasks if t.status == TaskStatus.COMPLETED)
                comp_rate = completed / total if total else 0.0
                times = [
                    (t.completed_at - t.started_at).total_seconds()
                    for t in utasks
                    if t.status == TaskStatus.COMPLETED
                    and t.started_at is not None and t.completed_at is not None
                ]
                avg_time = sum(times) / len(times) if times else None
                ratings = [r for r in self._ratings if r.ratee_id == uid]
                rc = len(ratings)
                ra = sum(r.score for r in ratings) / rc if rc else 0.0
                rows.append({
                    "user_id": uid,
                    "username": user.username,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": comp_rate,
                    "average_completion_time": avg_time,
                    "rating_count": rc,
                    "rating_average": ra,
                })
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found")
            user = self._users[user_id]
            tids = self._tasks_by_assignee.get(user_id, set())
            tasks = [self._tasks[t] for t in tids if t in self._tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            comp_rate = completed / total if total else 0.0
            times = [
                (t.completed_at - t.started_at).total_seconds()
                for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None and t.completed_at is not None
            ]
            avg_time = sum(times) / len(times) if times else None
            ratings = [r for r in self._ratings if r.ratee_id == user_id]
            rc = len(ratings)
            ra = sum(r.score for r in ratings) / rc if rc else 0.0
            task_list = [
                {
                    "id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline,
                    "project_id": t.project_id,
                }
                for t in sorted(tasks, key=lambda t: t.id)
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": comp_rate,
                "average_completion_time": avg_time,
                "rating_count": rc,
                "rating_average": ra,
                "tasks": task_list,
            }

    def export_report(self, report, fmt):
        with self._lock:
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat instance")
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")

            report_type = report.get("report_type", "")

            if fmt == ReportFormat.CSV:
                buf = io.StringIO()
                writer = csv.writer(buf)
                if report_type == ReportType.TEAM_PERFORMANCE.value:
                    rows = report.get("rows", [])
                    header = ["user_id", "username", "total_tasks", "completed_tasks",
                              "completion_rate", "average_completion_time",
                              "rating_count", "rating_average"]
                    writer.writerow(header)
                    for row in rows:
                        writer.writerow([row.get(k, "") for k in header])
                elif report_type == ReportType.PROJECT_PROGRESS.value:
                    writer.writerow(["metric", "value"])
                    writer.writerow(["project_id", report.get("project_id", "")])
                    writer.writerow(["total_tasks", report.get("total_tasks", 0)])
                    writer.writerow(["completion_rate", report.get("completion_rate", 0.0)])
                    writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])
                    for status, count in report.get("status_counts", {}).items():
                        writer.writerow([status, count])
                elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
                    writer.writerow(["metric", "value"])
                    for key in ["user_id", "username", "total_tasks", "completed_tasks",
                                "in_progress_tasks", "not_started_tasks",
                                "completion_rate", "average_completion_time",
                                "rating_count", "rating_average"]:
                        writer.writerow([key, report.get(key, "")])
                else:
                    writer.writerow(["key", "value"])
                    for k, v in report.items():
                        if not isinstance(v, (list, dict)):
                            writer.writerow([k, v])
                return buf.getvalue()

            else:  # PDF
                title = str(report_type)
                return _build_pdf(title)


# ---------------------------------------------------------------------------
# Minimal PDF generator
# ---------------------------------------------------------------------------
def _build_pdf(title):
    safe = "".join(
        c if 32 <= ord(c) < 127 and c not in "()\\" else "?"
        for c in str(title)
    )
    stream = ("BT /F1 12 Tf 72 720 Td (" + safe + ") Tj ET").encode("ascii")

    pdf = b"%PDF-1.4\n"
    off1 = len(pdf)
    pdf += b"1 0 obj\n<</Type /Catalog /Pages 2 0 R>>\nendobj\n"
    off2 = len(pdf)
    pdf += b"2 0 obj\n<</Type /Pages /Kids [3 0 R] /Count 1>>\nendobj\n"
    off3 = len(pdf)
    pdf += (
        b"3 0 obj\n<</Type /Page /Parent 2 0 R /MediaBox [0 0 612 792]"
        b" /Contents 4 0 R /Resources <</Font <</F1 <</Type /Font"
        b" /Subtype /Type1 /BaseFont /Helvetica>>>>>>>>\nendobj\n"
    )
    off4 = len(pdf)
    pdf += b"4 0 obj\n<</Length " + str(len(stream)).encode() + b">>\nstream\n"
    pdf += stream
    pdf += b"\nendstream\nendobj\n"

    xref_pos = len(pdf)
    pdf += b"xref\n0 5\n"
    pdf += b"0000000000 65535 f \n"
    pdf += "{:010d} 00000 n \n".format(off1).encode()
    pdf += "{:010d} 00000 n \n".format(off2).encode()
    pdf += "{:010d} 00000 n \n".format(off3).encode()
    pdf += "{:010d} 00000 n \n".format(off4).encode()
    pdf += b"trailer\n<</Size 5 /Root 1 0 R>>\n"
    pdf += b"startxref\n" + str(xref_pos).encode() + b"\n%%EOF\n"
    return pdf
